// Day of week: 2=Tuesday, 4=Thursday, 6=Saturday (UTC)
const day = new Date().getUTCDay();
const typeMap = { 2: 'news', 4: 'evergreen', 6: 'conversion' };
const articleType = typeMap[day] ?? 'news';

// Publish date = tomorrow at 9am MST (UTC-7)
const publishDate = new Date();
publishDate.setUTCDate(publishDate.getUTCDate() + 1);
publishDate.setUTCHours(16, 0, 0, 0);

return [{ json: { article_type: articleType, publish_date: publishDate.toISOString().split('T')[0] } }];

const articleType = $input.first().json.article_type;
const publishDate = $input.first().json.publish_date;

// Non-news types: skip RSS entirely, agent picks topic from its own lists
if (articleType !== 'news') {
  return [{ json: { article_type: articleType, topic_seed: '', publish_date: publishDate } }];
}

// News type: try RSS, fall back gracefully so workflow never stops on RSS failure
let headline = 'GTA 6 latest news';
try {
  const feeds = [
    'https://www.gamesradar.com/rss/gta-6/',
    'https://www.reddit.com/r/GTA6/.rss?limit=5'
  ];
  for (const url of feeds) {
    try {
      const resp = await fetch(url, { headers: { 'User-Agent': 'DecodedSix/1.0' }, signal: AbortSignal.timeout(8000) });
      if (!resp.ok) continue;
      const xml = await resp.text();
      // Try CDATA title first, then plain title
      const cdata = xml.match(/<item>[\s\S]*?<title><!\[CDATA\[([^\]]+)\]\]><\/title>/);
      const plain = xml.match(/<item>[\s\S]*?<title>([^<]+)<\/title>/);
      const found = cdata?.[1] || plain?.[1];
      if (found && found.trim()) { headline = found.trim(); break; }
    } catch (_) { /* try next feed */ }
  }
} catch (_) { /* use fallback headline */ }

return [{ json: { article_type: articleType, topic_seed: headline, publish_date: publishDate } }];

const response = $input.first().json;
if (!response.success) {
  throw new Error(`Content agent failed: ${JSON.stringify(response)}`);
}
return [{ json: { status: 'queued', message: 'DSX-CA1 running in background — article will appear in HITL queue when ready' } }];
